        if id_num not in book_ratings:
            book_ratings[id_num] = []
        try:
            book_ratings[id_num].append(float(r['rating']))
        except ValueError:
            continue

# Calculate averages and filter
result_titles = []
for id_num, ratings in book_ratings.items():
    if not ratings:
        continue
    avg_rating = sum(ratings) / len(ratings)
    if avg_rating >= 4.5:
        result_titles.append(book_map[id_num])

print("__RESULT__:")
